inserted = 0
skipped = 0
for market, qty, entry, exit_p, open_fee, close_fee, fund_fee, ttype, pnl, tstr in trades:
    trade_dt = datetime.strptime(tstr, FMT)
    dt_str = trade_dt.strftime("%Y-%m-%d %H:%M:%S")
    direction = 'LONG' if exit_p >= entry else 'SHORT'
    outcome = 'win' if pnl > 0 else 'loss'
    cur.execute("""
        SELECT id FROM trades
        WHERE market=?
          AND strftime('%Y-%m-%d %H:%M', COALESCE(trade_datetime, ''))=?
          AND ABS(entry_price - ?) < 0.001
          AND ABS(COALESCE(qty, 0) - ?) < 0.0001
    """, (market, trade_dt.strftime("%Y-%m-%d %H:%M"), entry, qty))
    if cur.fetchone():
        skipped += 1
        continue
    cur.execute("""
        INSERT INTO trades
            (market, trade_type, qty, entry_price, exit_price,
             opening_fee, closing_fee, funding_fee, pnl_usdt,
             direction, outcome, trade_datetime,
             position_size_usdt, leverage, rule_violations)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)
    """, (
        market, ttype, qty, entry, exit_p,
        open_fee, close_fee, fund_fee, round(pnl, 8),
        direction, outcome, dt_str,
        round(entry * qty, 2), 1, '[]'
    ))
    inserted += 1

conn.commit()
conn.close()
print(f'Done: inserted={inserted}, skipped={skipped}')
